import re

img_src = 'data:image/jpeg;base64,'

with open("public/index.html", "r", encoding="utf-8") as f:
    html = f.read()

# Replace the entire intro-card div content
old = """      <div class="intro-card">
        <div class="iqm">"</div>
        <p class="iqt">Her yolculuk bir varış noktasıyla değil, ne hissetmek istediğinize dair bir sohbetle başlar.</p>
        <div class="istats">
          <div><div class="sn">12+</div><div class="sl">Destinasyon</div></div>
          <div><div class="sn">100%</div><div class="sl">Kişiye Özel</div></div>
          <div><div class="sn">24/7</div><div class="sl">Destek</div></div>
          <div><div class="sn">∞</div><div class="sl">Olasılık</div></div>
        </div>
      </div>"""

new = """      <div class="intro-card" style="padding:0;overflow:hidden;border-radius:12px;">
        <img src=\"""" + '"' + """" + img_src + \"""" + '"' + """" style="width:100%;height:100%;object-fit:cover;display:block;">
      </div>"""

if old in html:
    html = html.replace(old, new)
    print("REPLACED!")
else:
    print("NOT FOUND - trying regex")
    import re
    html, n = re.subn(
        r'<div class="intro-card">.*?</div>\s*</div>',
        '<div class="intro-card" style="padding:0;overflow:hidden;border-radius:12px;"><img src="' + img_src + '" style="width:100%;height:100%;object-fit:cover;display:block;"></div>',
        html, count=1, flags=re.DOTALL
    )
    print(f"Regex replaced: {n}")

with open("public/index.html", "w", encoding="utf-8") as f:
    f.write(html)
print("done")
